import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface Variant {
  name: string;
  conversionRate: number;
  visitors: number;
  conversions: number;
}

interface AbTestData {
  testName: string;
  variants: Variant[];
  confidenceLevel: number;
  liftPercentage: number;
}

export default function Widget() {
  const abTestData = response.data.data as AbTestData;
  const { testName, variants, liftPercentage } = abTestData;
  const { theme, primaryColor } = response.data.meta;
  const isPositiveLift = liftPercentage >= 0;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'dark' ? '#2D2D2D' : '#FFFFFF' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {testName}
            </Typography>
            <Stack direction="row" spacing={0.5} alignItems="center">
              {isPositiveLift ? <TrendingUp sx={{ fontSize: 18, color: primaryColor }} /> : <TrendingDown sx={{ fontSize: 18, color: primaryColor }} />}
              <Typography variant="h5" fontWeight={600} sx={{ color: primaryColor }}>
                {liftPercentage}%
              </Typography>
            </Stack>
            <Typography variant="caption" color="text.secondary">
              Lift Percentage
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: variants.map(v => v.conversionRate * 100),
                color: primaryColor,
              },
            ]}
            xAxis={[
              {
                data: variants.map(v => v.name),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: theme === 'dark' ? '#FFFFFF' : '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />

          <Stack direction="row" spacing={0.5}>
            {variants.map((variant, index) => (
              <Chip
                key={index}
                label={`${variant.name}: ${variant.conversionRate * 100}%`}
                sx={{ fontSize: '11px', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
